record.field:
for partner in records:
    if partner.x_gdpr_blocked and partner.email:
        # Ensure blacklist
        Blacklist = env['mail.blacklist'].sudo()
        if not Blacklist.search([('email', '=ilike', partner.email)], limit=1):
            Blacklist.create({'email': partner.email.lower().strip()})
    # Ensure opt_out
    if partner.x_gdpr_blocked:
        partner.write({'opt_out': True})
    # Kill pending activities
    env['mail.activity'].sudo().search([
        ('res_model', '=', 'res.partner'),
        ('res_id', '=', partner.id),
    ]).unlink()

for partner in records:
    # Cancel marketing automation participants
    try:
        env['marketing.participant'].sudo().search([
            ('partner_id', '=', partner.id),
            ('state', 'not in', ['completed', 'canceled']),
        ]).write({'state': 'canceled'})
    except Exception:
        pass
    # Opt-out mailing contacts
    try:
        if partner.email:
            contacts = env['mailing.contact'].sudo().search([
                ('email', '=ilike', partner.email),
                ('opt_out', '=', False),
            ])
            contacts.write({'opt_out': True})
    except Exception:
        pass
